export interface ChatMessage {
    id: string;
    role: 'user' | 'assistant' | 'system';
    content: string;
    timestamp: number;
    metadata?: {
        model?: string;
        tokens?: number;
        image?: string;
        audio?: string;
    };
}

export interface ChatSession {
    id: string;
    title: string;
    messages: ChatMessage[];
    createdAt: number;
    updatedAt: number;
    systemPrompt?: string;
}

export interface ChatConfig {
    temperature: number;
    maxTokens: number;
    topP: number;
    frequencyPenalty: number;
    presencePenalty: number;
}

export class ChatSystem {
    private engine: unknown;
    private isInitialized: boolean = false;
    private sessions: Map<string, ChatSession> = new Map();
    private currentSessionId: string | null = null;
    private defaultConfig: ChatConfig = {
        temperature: 0.7,
        maxTokens: 2000,
        topP: 1,
        frequencyPenalty: 0,
        presencePenalty: 0
    };

    constructor(engine: unknown) {
        this.engine = engine;
    }

    async init(): Promise<void> {
        if (this.isInitialized) return;

        console.log('[ChatSystem] 初始化对话系统...');

        this.loadSessions();

        if (this.sessions.size === 0) {
            this.createSession('新对话');
        } else if (!this.currentSessionId) {
            const sessions = Array.from(this.sessions.values());
            const sorted = sessions.sort((a, b) => b.updatedAt - a.updatedAt);
            this.currentSessionId = sorted[0].id;
        }

        this.isInitialized = true;
        console.log('[ChatSystem] 对话系统初始化完成, 当前会话:', this.currentSessionId);
    }

    private loadSessions(): void {
        const saved = localStorage.getItem('chat_sessions');
        if (saved) {
            try {
                const data = JSON.parse(saved);
                const sessions: ChatSession[] = Array.isArray(data) ? data : (data.sessions || []);
                sessions.forEach(s => this.sessions.set(s.id, s));
                
                if (data.currentSessionId && this.sessions.has(data.currentSessionId)) {
                    this.currentSessionId = data.currentSessionId;
                } else if (sessions.length > 0) {
                    const sorted = sessions.sort((a, b) => b.updatedAt - a.updatedAt);
                    this.currentSessionId = sorted[0].id;
                }
            } catch (e) {
                console.error('[ChatSystem] 加载对话历史失败:', e);
            }
        }
    }

    private saveSessions(): void {
        const sessions = Array.from(this.sessions.values());
        localStorage.setItem('chat_sessions', JSON.stringify({
            sessions,
            currentSessionId: this.currentSessionId
        }));
    }

    private getActiveAPI(): { endpoint: string; apiKey: string; model: string } | null {
        const saved = localStorage.getItem('settings_config');
        if (!saved) return null;

        try {
            const config = JSON.parse(saved);
            const items = config?.apiPool?.items || [];
            const activeId = config?.apiPool?.activeItemId;

            if (activeId) {
                const activeItem = items.find((item: { id: string }) => item.id === activeId);
                if (activeItem && activeItem.enabled) {
                    const model = activeItem.models.find((m: { enabled: boolean }) => m.enabled);
                    return {
                        endpoint: activeItem.endpoint,
                        apiKey: activeItem.apiKey,
                        model: model?.modelId || activeItem.models[0]?.modelId || ''
                    };
                }
            }

            const enabledItem = items.find((item: { enabled: boolean }) => item.enabled);
            if (enabledItem) {
                const model = enabledItem.models.find((m: { enabled: boolean }) => m.enabled);
                return {
                    endpoint: enabledItem.endpoint,
                    apiKey: enabledItem.apiKey,
                    model: model?.modelId || enabledItem.models[0]?.modelId || ''
                };
            }

            return null;
        } catch (e) {
            console.error('[ChatSystem] 获取API配置失败:', e);
            return null;
        }
    }

    createSession(title: string = '新对话', systemPrompt?: string): ChatSession {
        const defaultSystemPrompt = `你是一个RPG游戏的AI助手和游戏主持人。你的回复必须包含结构化的游戏指令，格式如下：

【叙事内容】
用生动的语言描述场景和剧情...

【游戏指令】
\`\`\`json
{
  "actions": [
    {"type": "add_gold", "value": 50, "reason": "发现宝藏"},
    {"type": "add_exp", "value": 20, "reason": "完成对话"},
    {"type": "add_item", "item": "治疗药水", "quantity": 1},
    {"type": "trigger_event", "event": "神秘商人出现"},
    {"type": "change_location", "location": "酒馆"},
    {"type": "start_combat", "enemy": "哥布林", "level": 3},
    {"type": "show_choices", "choices": ["选项1", "选项2", "选项3"]}
  ]
}
\`\`\`

支持的指令类型：
- add_gold: 增加金币 (value: 数量)
- add_exp: 增加经验 (value: 数量)
- add_item: 获得物品 (item: 物品名, quantity: 数量)
- remove_item: 移除物品
- trigger_event: 触发事件 (event: 事件名)
- change_location: 切换场景 (location: 场景名)
- start_combat: 开始战斗 (enemy: 敌人名, level: 等级)
- show_choices: 显示选项 (choices: 选项数组)
- set_flag: 设置标记 (flag: 标记名, value: 值)
- check_stat: 检查属性 (stat: 属性名)

每次回复都必须包含【叙事内容】和【游戏指令】两部分。指令可以是空数组表示无操作。`;

        const session: ChatSession = {
            id: `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            title,
            messages: [],
            createdAt: Date.now(),
            updatedAt: Date.now(),
            systemPrompt: systemPrompt || defaultSystemPrompt
        };

        this.sessions.set(session.id, session);
        this.currentSessionId = session.id;
        this.saveSessions();

        return session;
    }

    getCurrentSession(): ChatSession | null {
        if (!this.currentSessionId) return null;
        return this.sessions.get(this.currentSessionId) || null;
    }

    getSessions(): ChatSession[] {
        return Array.from(this.sessions.values()).sort((a, b) => b.updatedAt - a.updatedAt);
    }

    switchSession(sessionId: string): boolean {
        if (this.sessions.has(sessionId)) {
            this.currentSessionId = sessionId;
            return true;
        }
        return false;
    }

    deleteSession(sessionId: string): boolean {
        if (this.sessions.has(sessionId)) {
            this.sessions.delete(sessionId);
            this.saveSessions();

            if (this.currentSessionId === sessionId) {
                const sessions = this.getSessions();
                this.currentSessionId = sessions.length > 0 ? sessions[0].id : null;
            }

            return true;
        }
        return false;
    }

    clearSession(sessionId: string): boolean {
        const session = this.sessions.get(sessionId);
        if (session) {
            session.messages = [];
            session.updatedAt = Date.now();
            this.saveSessions();
            return true;
        }
        return false;
    }

    async sendMessage(
        content: string,
        config?: Partial<ChatConfig>
    ): Promise<ChatMessage> {
        const session = this.getCurrentSession();
        if (!session) {
            throw new Error('没有活动的对话会话');
        }

        const userMessage: ChatMessage = {
            id: `msg_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            role: 'user',
            content,
            timestamp: Date.now()
        };

        session.messages.push(userMessage);
        session.updatedAt = Date.now();
        this.saveSessions();

        try {
            const response = await this.callAI(session, content, config);

            const assistantMessage: ChatMessage = {
                id: `msg_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
                role: 'assistant',
                content: response.content,
                timestamp: Date.now(),
                metadata: {
                    model: response.model,
                    tokens: response.tokens
                }
            };

            session.messages.push(assistantMessage);
            session.updatedAt = Date.now();

            if (session.title === '新对话' && session.messages.length <= 2) {
                session.title = content.substring(0, 30) + (content.length > 30 ? '...' : '');
            }

            this.saveSessions();

            return assistantMessage;
        } catch (error) {
            console.error('[ChatSystem] 发送消息失败:', error);

            const errorMessage: ChatMessage = {
                id: `msg_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
                role: 'assistant',
                content: `抱歉，发生了错误：${error instanceof Error ? error.message : '未知错误'}`,
                timestamp: Date.now()
            };

            session.messages.push(errorMessage);
            this.saveSessions();

            return errorMessage;
        }
    }

    private async callAI(
        session: ChatSession,
        userContent: string,
        config?: Partial<ChatConfig>
    ): Promise<{ content: string; model: string; tokens?: number }> {
        const api = this.getActiveAPI();

        if (!api) {
            throw new Error('请先在API卡池中配置并激活一个API');
        }

        if (!api.apiKey) {
            throw new Error('API密钥未设置，请在API卡池中配置');
        }

        if (!api.model) {
            throw new Error('未选择模型，请在API卡池中配置模型');
        }

        const messages: Array<{ role: string; content: string }> = [];

        if (session.systemPrompt) {
            messages.push({ role: 'system', content: session.systemPrompt });
        }

        const recentMessages = session.messages.slice(-20);
        for (const msg of recentMessages) {
            if (msg.role !== 'system') {
                messages.push({ role: msg.role, content: msg.content });
            }
        }

        messages.push({ role: 'user', content: userContent });

        const finalConfig = { ...this.defaultConfig, ...config };

        const endpoint = api.endpoint.includes('/chat/completions')
            ? api.endpoint
            : api.endpoint.replace(/\/$/, '') + '/chat/completions';

        try {
            const response = await fetch(endpoint, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${api.apiKey}`
                },
                body: JSON.stringify({
                    model: api.model,
                    messages,
                    temperature: finalConfig.temperature,
                    max_tokens: finalConfig.maxTokens,
                    top_p: finalConfig.topP,
                    frequency_penalty: finalConfig.frequencyPenalty,
                    presence_penalty: finalConfig.presencePenalty
                })
            });

            if (!response.ok) {
                const errorData = await response.json().catch(() => ({}));
                throw new Error(errorData.error?.message || `API请求失败: ${response.status}`);
            }

            const data = await response.json();

            return {
                content: data.choices[0].message.content,
                model: api.model,
                tokens: data.usage?.total_tokens
            };
        } catch (error) {
            if (error instanceof Error) {
                throw error;
            }
            throw new Error('网络请求失败，请检查网络连接');
        }
    }

    updateConfig(config: Partial<ChatConfig>): void {
        Object.assign(this.defaultConfig, config);
        localStorage.setItem('chat_config', JSON.stringify(this.defaultConfig));
    }

    getConfig(): ChatConfig {
        const saved = localStorage.getItem('chat_config');
        if (saved) {
            try {
                Object.assign(this.defaultConfig, JSON.parse(saved));
            } catch (e) {
                console.error('[ChatSystem] 加载配置失败:', e);
            }
        }
        return { ...this.defaultConfig };
    }

    exportSession(sessionId: string): string | null {
        const session = this.sessions.get(sessionId);
        if (session) {
            return JSON.stringify(session, null, 2);
        }
        return null;
    }

    importSession(jsonData: string): ChatSession | null {
        try {
            const session = JSON.parse(jsonData) as ChatSession;
            session.id = `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
            this.sessions.set(session.id, session);
            this.saveSessions();
            return session;
        } catch (e) {
            console.error('[ChatSystem] 导入会话失败:', e);
            return null;
        }
    }
}

export default ChatSystem;
